('FORM-MC-001', '中古风风格搭配公式', 'style', 'MC', 'LIVING_ROOM', 10, $STYLE_JSON${"must_have":[{"type":"material","values":["胡桃木","羊羔绒"],"role":"primary"}],"compatible":[{"type":"material","values":["皮革","大理石","藤编","金属"],"weight":0.28,"reason":"风格标志性材质组合"},{"type":"color","relation":"analogous","values":["奶油白","深棕","木色"],"weight":0.33,"reason":"核心配色体系"},{"type":"category","values":["沙发","茶几","休闲椅"],"weight":0.28,"reason":"典型家具组合"},{"type":"scene","values":["客厅","书房"],"weight":0.11}],"avoid":[{"type":"mood","values":["过度繁复的古典装饰（如大量雕花、描金、华丽吊灯）"],"reason":"风格禁忌"},{"type":"material","values":["金属"],"reason":"冷色调金属与镜面为主的轻奢元素"},{"type":"mood","values":["高饱和荧光色或过于鲜艳的色彩搭配"],"reason":"风格禁忌"},{"type":"mood","values":["工业化流水线感强的廉价仿制品家具"],"reason":"风格禁忌"}],"spatial_hint":{"note":"有机现代主义原则：将自然有机曲线与现代主义功能理性相融合，追求'形式追随功能'的同时以流畅形态赋予空间人文温度（Attfield, 1997; Havenhand, 2019）"}}$STYLE_JSON$::jsonb, $STYLE_JSON$["CASE-MC-001"]$STYLE_JSON$::jsonb, $STYLE_JSON$[]$STYLE_JSON$::jsonb, 10, 1, 'active', 'system', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
